#include <iostream>
#include <queue>
#include <string>
#include <vector>
using namespace std;struct Node{int val;vector<Node*>ch;Node(int v):val(v){}};struct TreeNode{int val;TreeNode*left=nullptr,*right=nullptr;TreeNode(int v):val(v){}};void split(const string&s,vector<string>&t){string cur;for(char c:s){if(c==','){t.push_back(cur);cur.clear();}else cur+=c;}t.push_back(cur);}Node* parse(string s){if(s=="[]")return nullptr;vector<string>tok;split(s.substr(1,s.size()-2),tok);Node*root=new Node(stoi(tok[0]));queue<Node*>q;q.push(root);int i=1;if(i<tok.size()&&tok[i]=="null")i++;while(!q.empty()&&i<tok.size()){Node*p=q.front();q.pop();while(i<tok.size()&&tok[i]!="null"){Node*c=new Node(stoi(tok[i++]));p->ch.push_back(c);q.push(c);}if(i<tok.size()&&tok[i]=="null")i++;}return root;}TreeNode* enc(Node*r){if(!r)return nullptr;TreeNode*b=new TreeNode(r->val),*prev=nullptr;for(auto*c:r->ch){TreeNode*e=enc(c);if(!prev)b->left=e;else prev->right=e;prev=e;}return b;}Node* dec(TreeNode*r){if(!r)return nullptr;Node*n=new Node(r->val);for(TreeNode*c=r->left;c;c=c->right)n->ch.push_back(dec(c));return n;}string fmt(Node*r){if(!r)return"[]";vector<string>out{to_string(r->val),"null"};queue<Node*>q;q.push(r);while(!q.empty()){Node*p=q.front();q.pop();for(auto*c:p->ch){out.push_back(to_string(c->val));q.push(c);}out.push_back("null");}while(!out.empty()&&out.back()=="null")out.pop_back();string s="[";for(int i=0;i<out.size();i++){if(i)s+=",";s+=out[i];}return s+"]";}int main(){ios::sync_with_stdio(false);cin.tie(nullptr);int t;string line;if(!(cin>>t))return 0;for(int i=0;i<t;i++){cin>>line;if(i)cout<<"\n\n";cout<<fmt(dec(enc(parse(line))));}}
